package org.smart_elder_system.gateway.filter;

import io.jsonwebtoken.Claims;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.security.Keys;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.cloud.gateway.filter.GatewayFilterChain;
import org.springframework.cloud.gateway.filter.GlobalFilter;
import org.springframework.core.Ordered;
import org.springframework.core.io.buffer.DataBuffer;
import org.springframework.core.io.buffer.DataBufferFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.http.server.reactive.ServerHttpRequest;
import org.springframework.http.server.reactive.ServerHttpResponse;
import org.springframework.stereotype.Component;
import org.springframework.boot.context.properties.ConfigurationProperties;
import org.springframework.boot.context.properties.EnableConfigurationProperties;
import org.springframework.util.CollectionUtils;
import org.springframework.util.StringUtils;
import org.springframework.web.server.ServerWebExchange;
import reactor.core.publisher.Mono;

import javax.crypto.SecretKey;
import java.nio.charset.StandardCharsets;
import java.util.List;
import java.util.Objects;
import java.util.stream.Collectors;

@Component
@EnableConfigurationProperties(GlobalAuthFilter.AuthWhitelistProperties.class)
public class GlobalAuthFilter implements GlobalFilter, Ordered {

    private static final Logger log = LoggerFactory.getLogger(GlobalAuthFilter.class);

    @Value("${jwt.secret}")
    private String secret;

    private final AuthWhitelistProperties authWhitelistProperties;

    @Autowired
    public GlobalAuthFilter(AuthWhitelistProperties authWhitelistProperties) {
        this.authWhitelistProperties = authWhitelistProperties;
    }

    @Override
    public Mono<Void> filter(ServerWebExchange exchange, GatewayFilterChain chain) {
        ServerHttpRequest request = exchange.getRequest();
        String path = request.getPath().value();
        
        List<String> whitelist = authWhitelistProperties.getPaths();
        if (!CollectionUtils.isEmpty(whitelist)
                && whitelist.stream().filter(Objects::nonNull).anyMatch(path::startsWith)) {
            return chain.filter(exchange);
        }

        if (!StringUtils.hasText(secret)) {
            log.error("JWT secret is empty");
            return writeUnauthorized(exchange);
        }

        // 从请求头中获取token
        String token = request.getHeaders().getFirst("Authorization");
        
        if (StringUtils.hasText(token) && token.startsWith("Bearer ")) {
            token = token.substring(7); // 移除 "Bearer " 前缀
            
            try {
                // 验证token
                SecretKey key = Keys.hmacShaKeyFor(secret.getBytes(StandardCharsets.UTF_8));
                Claims claims = Jwts.parser()
                        .verifyWith(key)
                        .build()
                        .parseSignedClaims(token)
                        .getPayload();
                
                // 将用户信息添加到请求头中，转发给下游服务
                String username = claims.getSubject();
                Object userIdClaim = claims.get("userId");
                Object permissionsClaim = claims.get("permissions");
                Object rolesClaim = claims.get("roles");
                String userId = userIdClaim == null ? "" : String.valueOf(userIdClaim);
                String permissions = permissionsClaim instanceof List<?> permissionList
                        ? permissionList.stream().map(String::valueOf).collect(Collectors.joining(","))
                        : "";
                String roles = rolesClaim instanceof List<?> roleList
                        ? roleList.stream().map(String::valueOf).collect(Collectors.joining(","))
                        : "";
                ServerHttpRequest modifiedRequest = request.mutate()
                        .header("X-User-Name", username)
                        .header("X-User-Id", userId)
                        .header("X-User-Permissions", permissions)
                        .header("X-User-Roles", roles)
                        .build();
                
                return chain.filter(exchange.mutate().request(modifiedRequest).build());
            } catch (Exception e) {
                log.error("JWT token validation failed", e);
            }
        }
        
        return writeUnauthorized(exchange);
    }

    private Mono<Void> writeUnauthorized(ServerWebExchange exchange) {
        ServerHttpResponse response = exchange.getResponse();
        response.setStatusCode(HttpStatus.UNAUTHORIZED);
        response.getHeaders().add("Content-Type", MediaType.APPLICATION_JSON_VALUE);

        DataBufferFactory bufferFactory = response.bufferFactory();
        DataBuffer buffer = bufferFactory.wrap("{\"code\":401,\"message\":\"未授权或token已过期\"}".getBytes(StandardCharsets.UTF_8));

        return response.writeWith(Mono.just(buffer));
    }

    @Override
    public int getOrder() {
        return 0;
    }

    @ConfigurationProperties(prefix = "auth.whitelist")
    public static class AuthWhitelistProperties {

        private List<String> paths;

        public List<String> getPaths() {
            return paths;
        }

        public void setPaths(List<String> paths) {
            this.paths = paths;
        }
    }
}